package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithEscape() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        char escape = '\\';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        Method withEscapeMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
        withEscapeMethod.setAccessible(true);
        CSVFormat result = (CSVFormat) withEscapeMethod.invoke(csvFormat, escape);

        // Then
        assertEquals(escape, result.getEscapeCharacter());
    }
}
